{"version":3,"sources":["../../../../components/layout/app-sidebar.tsx","../../../../components/layout/top-navbar.tsx","../../../../app/%28dashboard%29/layout.tsx","../../../../node_modules/lucide-react/src/icons/log-out.ts"],"sourcesContent":["\"use client\"\n\nimport Link from \"next/link\"\nimport { usePathname, useRouter } from \"next/navigation\"\nimport type { MouseEvent } from \"react\"\nimport { LogOut, ChevronUp } from \"lucide-react\"\nimport { useAuthStore } from \"@/store/auth-store\"\nimport { NAV_ITEMS, ROLE_SHORT_LABELS } from \"@/lib/constants\"\nimport {\n  Sidebar,\n  SidebarContent,\n  SidebarFooter,\n  SidebarGroup,\n  SidebarGroupContent,\n  SidebarGroupLabel,\n  SidebarHeader,\n  SidebarMenu,\n  SidebarMenuButton,\n  SidebarMenuItem,\n  useSidebar,\n} from \"@/components/ui/sidebar\"\nimport {\n  DropdownMenu,\n  DropdownMenuContent,\n  DropdownMenuItem,\n  DropdownMenuSeparator,\n  DropdownMenuTrigger,\n} from \"@/components/ui/dropdown-menu\"\nimport { Avatar, AvatarFallback } from \"@/components/ui/avatar\"\nimport { cn } from \"@/lib/utils\"\nimport { BrandWordmark } from \"@/components/shared/brand-wordmark\"\nimport { cleanupHydraulicWorkspaceSession } from \"@/lib/hydraulic-workspace\"\n\nconst HYDRAULIC_TESTER_EMAIL = \"admin2@hydranet.com\"\nconst HYDRAULIC_NAV_ROUTES = new Set([\n  \"/dashboard/hydraulic-model\",\n  \"/dashboard/hydraulic-reports\",\n])\n\nexport function AppSidebar() {\n  const pathname = usePathname()\n  const router = useRouter()\n  const { currentUser, logout } = useAuthStore()\n  const { state, isMobile, setOpenMobile } = useSidebar()\n  const isCollapsed = !isMobile && state === \"collapsed\"\n  const isHydraulicWorkspace = pathname === \"/dashboard/hydraulic-model/workspace\"\n\n  if (!currentUser) return null\n\n  const isHydraulicTester = currentUser.email?.trim().toLowerCase() === HYDRAULIC_TESTER_EMAIL\n  const visibleItems = NAV_ITEMS.filter((item) => {\n    if (!item.roles.includes(currentUser.role)) return false\n    if (HYDRAULIC_NAV_ROUTES.has(item.href)) return isHydraulicTester\n    return true\n  })\n\n  const initials = currentUser.name\n    .split(\" \")\n    .map((n) => n[0])\n    .join(\"\")\n    .toUpperCase()\n\n  async function handleWorkspaceNavigation(event: MouseEvent<HTMLElement>, href: string) {\n    if (isMobile) setOpenMobile(false)\n    if (!isHydraulicWorkspace || href === pathname) return\n\n    event.preventDefault()\n    await cleanupHydraulicWorkspaceSession()\n    router.push(href)\n  }\n\n  return (\n    <Sidebar \n      collapsible=\"icon\" \n      overlayExpandedDesktop={isHydraulicWorkspace}\n      className=\"border-r border-slate-300/80 bg-sidebar shadow-[8px_0_24px_-26px_rgba(15,23,42,0.38)]\"\n    >\n      <div className=\"absolute inset-0 bg-slate-200/45 pointer-events-none\" />\n      <div className=\"absolute top-0 left-0 right-0 h-px bg-slate-400/70\" />\n\n      <SidebarHeader className={cn(\n        \"border-b border-slate-300/80 relative bg-slate-200/55 backdrop-blur-sm\",\n        isCollapsed ? \"px-2 py-4\" : \"px-5 py-6\"\n      )}>\n        <Link href=\"/dashboard\" onClick={(event) => void handleWorkspaceNavigation(event, \"/dashboard\")} className={cn(\n          \"flex items-center\",\n          isCollapsed ? \"justify-center\" : \"gap-4\"\n        )}>\n          <div className={cn(\n            \"relative flex items-center justify-center\",\n            isCollapsed ? \"h-10 w-10\" : \"h-14 w-14\"\n          )}>\n            <div className={cn(\n              \"relative flex items-center justify-center rounded-xl border border-slate-300 bg-slate-100 shadow-sm shadow-slate-900/[0.04] transition-shadow duration-500 hover:shadow-slate-900/[0.08]\",\n              isCollapsed ? \"h-10 w-10\" : \"h-full w-full rounded-2xl\"\n            )}>\n              <img \n                src=\"/logo1.png\" \n                alt=\"MajiScope Logo\" \n                className={cn(\n                  \"object-contain rounded-lg\",\n                  isCollapsed ? \"h-6 w-6\" : \"h-9 w-9\"\n                )}\n              />\n            </div>\n          </div>\n\n          {!isCollapsed && (\n            <div className=\"flex flex-col gap-0.5\">\n              <div className=\"inline-flex self-start rounded-xl bg-slate-950 px-3 py-2 shadow-lg shadow-slate-950/15\">\n                <BrandWordmark\n                  size=\"sm\"\n                  theme=\"dark\"\n                  wordClassName=\"leading-none\"\n                  underlineClassName=\"mt-1 h-0.5\"\n                />\n              </div>\n              <span className=\"text-[10px] font-semibold uppercase tracking-[0.15em] text-slate-600 mt-2\">\n                Water Intelligence\n              </span>\n            </div>\n          )}\n        </Link>\n      </SidebarHeader>\n\n      <SidebarContent className={cn(\n        \"flex flex-col h-full relative\",\n        isCollapsed ? \"px-1 py-2\" : \"px-3 py-4\"\n      )}>\n        <SidebarGroup className=\"flex-1 flex flex-col h-full\">\n          <SidebarGroupLabel className={cn(\n            \"text-slate-500 text-[10px] uppercase tracking-[0.15em] font-semibold mb-2\",\n            isCollapsed ? \"px-0 text-center hidden\" : \"px-2\"\n          )}>\n            {!isCollapsed && \"Navigation\"}\n          </SidebarGroupLabel>\n          <SidebarGroupContent className=\"flex-1 flex flex-col\">\n            <SidebarMenu className={cn(\n              \"flex flex-col h-full\",\n              isCollapsed ? \"gap-0 items-center justify-between flex-1\" : \"gap-1.5\"\n            )}>\n              {visibleItems.map((item, index) => {\n                const isActive =\n                  pathname === item.href ||\n                  (item.href !== \"/dashboard\" && pathname.startsWith(item.href))\n\n                return (\n                  <SidebarMenuItem key={item.href} className={isCollapsed ? \"w-full flex justify-center flex-1\" : \"\"}>\n                    <SidebarMenuButton\n                      asChild\n                      isActive={isActive}\n                      tooltip={isMobile ? undefined : item.title}\n                      className={cn(\n                        \"relative transition-all duration-300 ease-out\",\n                        isCollapsed ? \"h-11 w-11 justify-center rounded-xl mx-auto\" : \"min-h-12 h-auto w-full rounded-xl justify-start px-4 py-2.5\",\n                        isActive \n                          ? \"bg-gradient-to-r from-sky-700 to-blue-700 text-white shadow-md shadow-slate-900/15 hover:from-sky-800 hover:to-blue-800 hover:shadow-lg hover:shadow-slate-900/20\" \n                          : \"text-slate-600 hover:text-slate-950 hover:bg-slate-300/55\",\n                        \"group overflow-hidden\"\n                      )}\n                      style={{ animationDelay: `${index * 50}ms` }}\n                    >\n                      <Link \n                        href={item.href} \n                        onClick={(event) => void handleWorkspaceNavigation(event, item.href)}\n                        className={cn(\n                          \"flex min-h-full w-full items-center\",\n                          isCollapsed ? \"justify-center\" : \"gap-4\"\n                        )}\n                      >\n                        <div className=\"relative flex h-6 w-6 items-center justify-center\">\n                          <item.icon className={cn(\n                            \"transition-colors duration-200\",\n                            isActive \n                              ? \"h-5 w-5 text-white\" \n                              : \"h-5 w-5 text-slate-700\"\n                          )} />\n                        </div>\n                        \n                        {!isCollapsed && (\n                          <span className={cn(\n                            \"max-w-[9.25rem] whitespace-normal break-words text-sm font-semibold leading-snug tracking-wide\",\n                            isActive ? \"text-white\" : \"\"\n                          )}>\n                            {item.title}\n                          </span>\n                        )}\n                        \n                      </Link>\n                    </SidebarMenuButton>\n                  </SidebarMenuItem>\n                )\n              })}\n            </SidebarMenu>\n          </SidebarGroupContent>\n        </SidebarGroup>\n      </SidebarContent>\n\n      <SidebarFooter className={cn(\n        \"border-t border-slate-300/80 bg-slate-200/55 relative\",\n        isCollapsed ? \"p-2\" : \"p-4\"\n      )}>\n        <div className=\"absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-slate-300 to-transparent\" />\n        \n        <SidebarMenu>\n          <SidebarMenuItem>\n            <DropdownMenu>\n              <DropdownMenuTrigger asChild>\n                <SidebarMenuButton\n                  size=\"lg\"\n                  className={cn(\n                    \"transition-all duration-300 rounded-xl\",\n                    isCollapsed ? \"p-2 h-11 w-11 justify-center mx-auto data-[state=open]:bg-slate-300/60\" : \"p-3 data-[state=open]:bg-slate-300/60 hover:bg-slate-300/50\"\n                  )}\n                >\n                  <div className=\"relative\">\n                    <Avatar className={cn(\n                      \"border-2 border-slate-300 shadow-md shadow-slate-900/[0.06]\",\n                      isCollapsed ? \"h-9 w-9\" : \"h-11 w-11\"\n                    )}>\n                      <AvatarFallback className=\"bg-slate-800 text-white text-sm font-bold\">\n                        {initials}\n                      </AvatarFallback>\n                    </Avatar>\n                    <span className={cn(\n                      \"absolute rounded-full bg-emerald-500 border-2 border-white shadow-sm\",\n                      isCollapsed ? \"-bottom-0.5 -right-0.5 h-3 w-3\" : \"-bottom-0.5 -right-0.5 h-3.5 w-3.5\"\n                    )} />\n                  </div>\n                  {!isCollapsed && (\n                    <div className=\"flex flex-col text-left text-sm leading-tight ml-2\">\n                      <span className=\"truncate font-semibold text-slate-800\">\n                        {currentUser.name}\n                      </span>\n                      <span className=\"truncate text-xs text-slate-600 font-medium\">\n                        {ROLE_SHORT_LABELS[currentUser.role]}\n                      </span>\n                    </div>\n                  )}\n                  {!isCollapsed && <ChevronUp className=\"ml-auto h-4 w-4 text-slate-400\" />}\n                </SidebarMenuButton>\n              </DropdownMenuTrigger>\n              <DropdownMenuContent\n                side=\"top\"\n                align={isCollapsed ? \"center\" : \"start\"}\n                className=\"w-60 bg-card/95 backdrop-blur-xl border-slate-200 shadow-xl shadow-slate-900/10 rounded-xl\"\n              >\n                <div className=\"p-3 bg-slate-100 rounded-t-lg\">\n                  <div className=\"flex items-center gap-3\">\n                    <Avatar className=\"h-10 w-10 border-2 border-slate-300\">\n                      <AvatarFallback className=\"bg-gradient-to-br from-sky-700 to-blue-700 text-white text-xs font-bold\">\n                        {initials}\n                      </AvatarFallback>\n                    </Avatar>\n                    <div>\n                      <p className=\"text-sm font-semibold text-slate-800\">{currentUser.name}</p>\n                      <p className=\"text-xs text-slate-500\">{currentUser.email}</p>\n                    </div>\n                  </div>\n                </div>\n                <DropdownMenuSeparator className=\"bg-slate-100\" />\n                <DropdownMenuItem\n                  onClick={() => {\n                    logout()\n                    window.location.href = \"/login\"\n                  }}\n                  className=\"text-red-600 focus:text-red-600 focus:bg-red-50 m-1 rounded-lg cursor-pointer\"\n                >\n                  <LogOut className=\"mr-2 h-4 w-4\" />\n                  Sign Out\n                </DropdownMenuItem>\n              </DropdownMenuContent>\n            </DropdownMenu>\n          </SidebarMenuItem>\n        </SidebarMenu>\n      </SidebarFooter>\n    </Sidebar>\n  )\n}\n","\"use client\"\n\nimport { useEffect, useMemo, useState } from \"react\"\nimport Image from \"next/image\"\nimport { usePathname, useRouter } from \"next/navigation\"\nimport {\n  Bell,\n  CheckCheck,\n  ChevronDown,\n  User,\n  LogOut,\n  Shield,\n  Moon,\n  Sun,\n  HelpCircle,\n  Activity,\n  Clock,\n  Loader2,\n  Settings,\n} from \"lucide-react\"\n\nimport { useAuthStore } from \"@/store/auth-store\"\nimport { useDataStore } from \"@/store/data-store\"\nimport { useTheme } from \"next-themes\"\nimport { SidebarTrigger, useSidebar } from \"@/components/ui/sidebar\"\nimport { Button } from \"@/components/ui/button\"\nimport { Avatar, AvatarFallback } from \"@/components/ui/avatar\"\nimport { useTopbarTitle } from \"@/components/layout/topbar-title-context\"\nimport {\n  DropdownMenu,\n  DropdownMenuContent,\n  DropdownMenuGroup,\n  DropdownMenuItem,\n  DropdownMenuSeparator,\n  DropdownMenuTrigger,\n} from \"@/components/ui/dropdown-menu\"\nimport { Tooltip, TooltipContent, TooltipTrigger } from \"@/components/ui/tooltip\"\nimport { getNotificationTag, resolveNotificationDestinationWithData } from \"@/lib/notifications\"\nimport { formatTanzaniaShortDate } from \"@/lib/date-time\"\nimport { cn } from \"@/lib/utils\"\nimport { DEFAULT_WEB_UI_PREFERENCES, loadWebUiPreferences, subscribeToWebUiPreferences } from \"@/lib/user-preferences\"\nimport { BrandWordmark } from \"@/components/shared/brand-wordmark\"\n\nexport function TopNavbar() {\n  const router = useRouter()\n  const pathname = usePathname()\n  const { state, isMobile } = useSidebar()\n  const { currentUser, logout } = useAuthStore()\n  const {\n    notifications,\n    fetchNotifications,\n    getUnreadNotificationCount,\n    markNotificationRead,\n    markAllNotificationsRead,\n  } = useDataStore()\n  const { resolvedTheme, setTheme } = useTheme()\n  const { title: topbarTitle } = useTopbarTitle()\n  const [notificationsOpen, setNotificationsOpen] = useState(false)\n  const [notificationsLoading, setNotificationsLoading] = useState(false)\n  const [markingAllRead, setMarkingAllRead] = useState(false)\n  const [mounted, setMounted] = useState(false)\n  const [uiPreferences, setUiPreferences] = useState(DEFAULT_WEB_UI_PREFERENCES)\n\n  const unreadCount = getUnreadNotificationCount()\n  const recentNotifications = useMemo(() => notifications.slice(0, 5), [notifications])\n  const isDarkMode = mounted && resolvedTheme === \"dark\"\n  const isHydraulicWorkspace = pathname === \"/dashboard/hydraulic-model/workspace\"\n  const shouldOffsetForHydraulicSidebar = isHydraulicWorkspace && !isMobile && state === \"expanded\"\n  const hydraulicSidebarOffset = \"calc(var(--sidebar-width) - var(--sidebar-width-icon))\"\n  const headerTitle = topbarTitle?.title || \"Water Leakage Monitoring\"\n  const titleHasMonitoringSuffix = headerTitle.endsWith(\" Monitoring\")\n  const titlePrimary = titleHasMonitoringSuffix ? headerTitle.replace(/ Monitoring$/, \"\") : headerTitle\n\n  useEffect(() => {\n    setMounted(true)\n  }, [])\n\n  useEffect(() => {\n    if (!mounted) return\n\n    const syncPreferences = () => {\n      setUiPreferences(loadWebUiPreferences())\n    }\n\n    syncPreferences()\n    return subscribeToWebUiPreferences(syncPreferences)\n  }, [mounted])\n\n  useEffect(() => {\n    if (!currentUser?.id) return\n\n    let active = true\n    const loadNotifications = async () => {\n      if (!active) return\n      setNotificationsLoading(true)\n      try {\n        await fetchNotifications(currentUser.id)\n      } finally {\n        if (active) {\n          setNotificationsLoading(false)\n        }\n      }\n    }\n\n    void loadNotifications()\n    const intervalId = window.setInterval(() => {\n      void fetchNotifications(currentUser.id)\n    }, uiPreferences.notificationRefreshSeconds * 1000)\n\n    return () => {\n      active = false\n      window.clearInterval(intervalId)\n    }\n  }, [currentUser?.id, fetchNotifications, uiPreferences.notificationRefreshSeconds])\n\n  const handleLogout = () => {\n    logout()\n    router.push(\"/login\")\n  }\n\n  const handleProfile = () => {\n    router.push(\"/dashboard/profile\")\n  }\n\n  const handleSettings = () => {\n    router.push(\"/dashboard/settings?section=preferences\")\n  }\n\n  const handleHelp = () => {\n    router.push(\"/dashboard/settings?section=help\")\n  }\n\n  const handleOpenNotificationsPage = () => {\n    setNotificationsOpen(false)\n    router.push(\"/dashboard/notifications\")\n  }\n\n  const handleOpenNotification = async (\n    notificationId: string,\n    title: string,\n    type: string,\n    link: string | null,\n    data?: Record<string, unknown> | null\n  ) => {\n    await markNotificationRead(notificationId)\n    setNotificationsOpen(false)\n\n    const resolution = resolveNotificationDestinationWithData({\n      id: notificationId,\n      title,\n      type,\n      link,\n      data,\n    })\n    router.push(resolution.destination || \"/dashboard/notifications\")\n  }\n\n  const handleMarkAllRead = async () => {\n    setMarkingAllRead(true)\n    try {\n      await markAllNotificationsRead()\n    } finally {\n      setMarkingAllRead(false)\n    }\n  }\n\n  const formatNotificationTime = (timestamp: string) => {\n    const date = new Date(timestamp)\n    const diffMs = Date.now() - date.getTime()\n    const diffMinutes = Math.max(1, Math.floor(diffMs / 60000))\n\n    if (diffMinutes < 60) return `${diffMinutes} minute${diffMinutes === 1 ? \"\" : \"s\"} ago`\n    const diffHours = Math.floor(diffMinutes / 60)\n    if (diffHours < 24) return `${diffHours} hour${diffHours === 1 ? \"\" : \"s\"} ago`\n    const diffDays = Math.floor(diffHours / 24)\n    if (diffDays < 7) return `${diffDays} day${diffDays === 1 ? \"\" : \"s\"} ago`\n    return formatTanzaniaShortDate(date, \"N/A\")\n  }\n\n  const getRoleBadgeColor = (role: string) => {\n    switch (role) {\n      case \"admin\":\n        return \"from-amber-600 to-orange-700\"\n      case \"utility_manager\":\n        return \"from-sky-700 to-blue-700\"\n      case \"dma_manager\":\n        return \"from-emerald-600 to-teal-700\"\n      default:\n        return \"from-slate-500 to-slate-600\"\n    }\n  }\n\n  const getRoleLabel = (role: string) => {\n    switch (role) {\n      case \"admin\":\n        return \"Administrator\"\n      case \"utility_manager\":\n        return \"Utility Manager\"\n      case \"dma_manager\":\n        return \"DMA Manager\"\n      default:\n        return \"User\"\n    }\n  }\n\n  return (\n    <header\n      className={cn(\n        \"sticky top-0 z-30 overflow-hidden transition-[margin,width] duration-200 ease-linear\",\n        shouldOffsetForHydraulicSidebar ? \"ml-0\" : \"w-full\"\n      )}\n      style={\n        shouldOffsetForHydraulicSidebar\n          ? {\n              marginLeft: hydraulicSidebarOffset,\n              width: `calc(100% - ${hydraulicSidebarOffset})`,\n            }\n          : undefined\n      }\n    >\n      {/* Calm command bar */}\n      <div className=\"relative flex h-16 w-full items-center justify-between gap-4 border-b border-slate-300/80 bg-slate-200/85 px-4 text-slate-800 shadow-sm shadow-slate-900/[0.025] backdrop-blur-xl dark:border-slate-800/80 dark:bg-slate-950/88 dark:text-slate-100 dark:shadow-black/30 sm:px-6\">\n        {/* Subtle background texture */}\n        <div className=\"pointer-events-none absolute inset-0 overflow-hidden\">\n          <div className=\"absolute left-1/2 top-0 h-px w-1/2 bg-gradient-to-r from-transparent via-slate-500/35 to-transparent\" />\n          \n          {/* Subtle Grid Pattern */}\n          <div \n            className=\"absolute inset-0 opacity-[0.02]\"\n            style={{\n              backgroundImage: `linear-gradient(rgba(255,255,255,.1) 1px, transparent 1px),\n                               linear-gradient(90deg, rgba(255,255,255,.1) 1px, transparent 1px)`,\n              backgroundSize: \"20px 20px\",\n            }}\n          />\n        </div>\n\n        <div className=\"relative z-10 flex min-w-0 items-center gap-3 sm:gap-4\">\n          {/* Sidebar Trigger with Glow */}\n          <div className=\"relative shrink-0\">\n            <SidebarTrigger className=\"-ml-1 text-slate-600 transition-all duration-300 hover:text-slate-900 dark:text-slate-300 dark:hover:text-white\" />\n          </div>\n\n          <div className=\"hidden min-w-0 items-center md:flex\">\n            <h1 className=\"relative inline-flex min-w-0 flex-col\">\n              <span className=\"truncate text-xl font-black leading-none tracking-tight lg:text-2xl\">\n                <span className=\"bg-gradient-to-r from-cyan-500 via-blue-600 to-teal-500 bg-clip-text text-transparent drop-shadow-sm dark:from-cyan-300 dark:via-blue-400 dark:to-teal-300\">\n                  {titlePrimary}\n                </span>\n                {titleHasMonitoringSuffix ? (\n                  <span className=\"bg-gradient-to-r from-slate-950 via-slate-700 to-slate-950 bg-clip-text text-transparent dark:from-white dark:via-cyan-100 dark:to-white\">\n                    {\" Monitoring\"}\n                  </span>\n                ) : null}\n              </span>\n              <span className=\"mt-1 h-0.5 w-24 rounded-full bg-gradient-to-r from-transparent via-cyan-500 to-transparent dark:via-cyan-400\" />\n            </h1>\n          </div>\n\n          {/* Styled MajiScope Name - Mobile Only */}\n          <div className=\"flex min-w-0 items-center gap-2.5 md:hidden\">\n            <div className=\"relative shrink-0\">\n              <div className=\"relative flex h-9 w-9 items-center justify-center overflow-hidden rounded-lg bg-slate-800 ring-1 ring-slate-500/20\">\n                <Image\n                  src=\"/logo1.png\"\n                  alt=\"MajiScope Logo\"\n                  width={28}\n                  height={28}\n                  className=\"object-contain\"\n                />\n              </div>\n            </div>\n            <BrandWordmark\n              size=\"sm\"\n              theme=\"dark\"\n              underline={false}\n              wordClassName=\"leading-none\"\n              className=\"shrink min-w-0\"\n            />\n          </div>\n        </div>\n\n        {/* Center Content - Theme, Help, Notifications */}\n        <div className=\"relative z-10 flex flex-1 items-center justify-end gap-2 sm:gap-3\">\n          {/* Theme Toggle MORDERN */}\n          <Tooltip>\n            <TooltipTrigger asChild>\n              <Button\n                variant=\"ghost\"\n                size=\"icon\"\n                onClick={() => setTheme(isDarkMode ? \"light\" : \"dark\")}\n                className=\"relative h-9 w-9 rounded-xl text-slate-600 transition-all duration-300 hover:bg-slate-100 hover:text-slate-900 dark:text-slate-300 dark:hover:bg-slate-800 dark:hover:text-white\"\n                aria-label={isDarkMode ? \"Switch to light mode\" : \"Switch to dark mode\"}\n              >\n                {isDarkMode ? <Sun className=\"h-4 w-4\" /> : <Moon className=\"h-4 w-4\" />}\n              </Button>\n            </TooltipTrigger>\n            <TooltipContent>\n              {isDarkMode ? \"Switch to light mode\" : \"Switch to dark mode\"}\n            </TooltipContent>\n          </Tooltip>\n\n          {/* Help Button */}\n          <Tooltip>\n            <TooltipTrigger asChild>\n              <Button\n                variant=\"ghost\"\n                size=\"icon\"\n                onClick={handleHelp}\n                className=\"relative hidden h-9 w-9 rounded-xl text-slate-600 transition-all duration-300 hover:bg-slate-100 hover:text-slate-900 dark:text-slate-300 dark:hover:bg-slate-800 dark:hover:text-white sm:flex\"\n                aria-label=\"Open help and support\"\n              >\n                <HelpCircle className=\"h-4 w-4\" />\n              </Button>\n            </TooltipTrigger>\n            <TooltipContent>\n              Open help and support\n            </TooltipContent>\n          </Tooltip>\n\n          {/* Notifications Dropdown */}\n          <DropdownMenu open={notificationsOpen} onOpenChange={setNotificationsOpen}>\n            <Tooltip>\n              <TooltipTrigger asChild>\n                <DropdownMenuTrigger asChild>\n                    <Button\n                      variant=\"ghost\"\n                      size=\"icon\"\n                      className=\"relative h-9 w-9 rounded-xl text-slate-600 transition-all duration-300 hover:bg-slate-100 hover:text-slate-900 dark:text-slate-300 dark:hover:bg-slate-800 dark:hover:text-white\"\n                      aria-label=\"Open notifications\"\n                    >\n                      <Bell className=\"h-4 w-4\" />\n                      {unreadCount > 0 ? (\n                        <span className=\"absolute -right-0.5 -top-0.5 flex h-4 min-w-4 items-center justify-center\">\n                          <span className=\"relative inline-flex h-4 min-w-4 items-center justify-center rounded-full bg-slate-800 px-1 text-[9px] font-bold text-white\">\n                            {unreadCount > 9 ? \"9+\" : unreadCount}\n                          </span>\n                        </span>\n                      ) : null}\n                    </Button>\n                </DropdownMenuTrigger>\n              </TooltipTrigger>\n              <TooltipContent>\n                Open notifications\n              </TooltipContent>\n            </Tooltip>\n            <DropdownMenuContent\n              align=\"end\"\n              className=\"z-[9999] w-80 rounded-xl border-white/10 bg-slate-900/95 p-0 backdrop-blur-xl\"\n            >\n              <div className=\"flex items-center justify-between border-b border-white/10 px-4 py-3\">\n                <div className=\"flex items-center gap-2\">\n                  <Bell className=\"h-4 w-4 text-sky-300\" />\n                  <span className=\"font-semibold text-white\">Notifications</span>\n                </div>\n                <div className=\"flex items-center gap-2\">\n                  <span className=\"rounded-full bg-sky-500/15 px-2 py-0.5 text-xs font-medium text-sky-300\">\n                    {unreadCount} unread\n                  </span>\n                  {unreadCount > 0 ? (\n                    <Button\n                      variant=\"ghost\"\n                      size=\"sm\"\n                      onClick={() => void handleMarkAllRead()}\n                      disabled={markingAllRead}\n                      className=\"h-7 rounded-lg px-2 text-xs text-sky-300 hover:bg-sky-500/10 hover:text-sky-200\"\n                    >\n                      {markingAllRead ? <Loader2 className=\"h-3.5 w-3.5 animate-spin\" /> : <CheckCheck className=\"h-3.5 w-3.5\" />}\n                    </Button>\n                  ) : null}\n                </div>\n              </div>\n              <div className=\"max-h-80 overflow-auto p-2\">\n                {notificationsLoading ? (\n                  <div className=\"flex items-center justify-center gap-2 rounded-lg px-3 py-8 text-sm text-slate-400\">\n                    <Loader2 className=\"h-4 w-4 animate-spin\" />\n                    Loading notifications...\n                  </div>\n                ) : recentNotifications.length > 0 ? (\n                  recentNotifications.map((notification) => (\n                    <button\n                      key={notification.id}\n                      type=\"button\"\n                      onClick={() => void handleOpenNotification(notification.id, notification.title, notification.type, notification.link, notification.data)}\n                      className={`flex w-full gap-3 rounded-lg p-3 text-left transition-colors hover:bg-white/5 ${\n                        notification.read ? \"\" : \"bg-sky-500/5\"\n                      }`}\n                    >\n                      <div\n                        className={`flex h-9 w-9 shrink-0 items-center justify-center rounded-lg ${\n                          notification.read ? \"bg-slate-500/20\" : \"bg-sky-500/15\"\n                        }`}\n                      >\n                        {notification.read ? (\n                          <Clock className=\"h-4 w-4 text-slate-300\" />\n                        ) : (\n                          <Bell className=\"h-4 w-4 text-sky-300\" />\n                        )}\n                      </div>\n                      <div className=\"min-w-0 flex-1\">\n                        <div className=\"flex items-center gap-2\">\n                          <p className=\"truncate text-sm font-medium text-white\">{notification.title}</p>\n                          {!notification.read ? (\n                            <span className=\"rounded-full bg-sky-500/15 px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-[0.14em] text-sky-200\">\n                              New\n                            </span>\n                          ) : null}\n                        </div>\n                        <p className=\"mt-1 line-clamp-2 text-xs text-slate-400\">{notification.message}</p>\n                        <div className=\"mt-2 flex items-center justify-between gap-2\">\n                          <span className=\"rounded-full bg-white/5 px-2 py-0.5 text-[10px] font-medium text-slate-300\">\n                            {getNotificationTag(notification)}\n                          </span>\n                          <p className=\"text-[10px] text-slate-500\">{formatNotificationTime(notification.createdAt)}</p>\n                        </div>\n                      </div>\n                    </button>\n                  ))\n                ) : (\n                  <div className=\"rounded-lg px-3 py-8 text-center\">\n                    <Bell className=\"mx-auto h-8 w-8 text-slate-500\" />\n                    <p className=\"mt-3 text-sm font-medium text-white\">No notifications yet</p>\n                    <p className=\"mt-1 text-xs text-slate-400\">Assignments, approvals, and alerts will appear here.</p>\n                  </div>\n                )}\n              </div>\n              <div className=\"border-t border-white/10 p-2\">\n                <Button\n                  variant=\"ghost\"\n                  onClick={handleOpenNotificationsPage}\n                  className=\"w-full justify-center rounded-lg text-sm text-sky-300 hover:bg-sky-500/10 hover:text-sky-200\"\n                >\n                  View all notifications\n                </Button>\n              </div>\n            </DropdownMenuContent>\n          </DropdownMenu>\n        </div>\n\n        <div className=\"relative z-10 ml-auto flex shrink-0 items-center gap-2 sm:gap-3\">\n          {/* Divider */}\n                <div className=\"hidden h-8 w-px bg-slate-200 dark:bg-slate-800 sm:block\" />\n\n          {/* User Profile Dropdown - Always at Right */}\n          <DropdownMenu>\n            <DropdownMenuTrigger asChild>\n              <Button\n                variant=\"ghost\"\n                className=\"relative flex h-auto items-center gap-3 rounded-xl px-2 py-1.5 transition-all duration-300 hover:bg-card dark:hover:bg-slate-900 sm:px-3\"\n              >\n                <div className=\"relative\">\n                  <Avatar className=\"relative h-12 w-12 ring-2 ring-slate-300 dark:ring-slate-700\">\n                    <AvatarFallback className=\"bg-gradient-to-br from-sky-700 to-blue-700 text-lg font-semibold text-white\">\n                      {currentUser?.name\n                        ?.split(\" \")\n                        .map((n) => n[0])\n                        .join(\"\")\n                        .toUpperCase() || \"U\"}\n                    </AvatarFallback>\n                  </Avatar>\n                  \n                  {/* Online Indicator */}\n                  <span className=\"absolute -bottom-0.5 -right-0.5 flex h-3 w-3 items-center justify-center rounded-full border-2 border-white bg-emerald-500 dark:border-slate-950\">\n                    <span className=\"h-1.5 w-1.5 rounded-full bg-white\" />\n                  </span>\n                </div>\n\n                {/* User Info - Desktop */}\n                <div className=\"hidden flex-col items-start sm:flex\">\n                  <span className=\"text-sm font-semibold text-slate-900 dark:text-slate-100\">\n                    {currentUser?.name || \"User\"}\n                  </span>\n                  <span className={`inline-flex items-center gap-1 rounded-full bg-gradient-to-r ${getRoleBadgeColor(currentUser?.role || \"\")} px-1.5 py-0.5 text-[9px] font-medium text-white`}>\n                    <Shield className=\"h-2 w-2\" />\n                    {getRoleLabel(currentUser?.role || \"\")}\n                  </span>\n                </div>\n\n                <ChevronDown className=\"hidden h-4 w-4 text-slate-500 transition-transform duration-200 group-data-[state=open]:rotate-180 dark:text-slate-400 sm:block\" />\n              </Button>\n            </DropdownMenuTrigger>\n\n            <DropdownMenuContent\n              align=\"end\"\n              className=\"z-[9999] w-72 rounded-xl border-white/10 bg-slate-900/95 p-0 backdrop-blur-xl\"\n            >\n              {/* Profile Header */}\n              <div className=\"relative overflow-hidden border-b border-white/10 p-4\">\n                {/* Background Gradient */}\n                <div className=\"pointer-events-none absolute inset-0 bg-gradient-to-br from-sky-700/10 via-transparent to-blue-700/10\" />\n                \n                <div className=\"relative flex items-center gap-3\">\n                  <div className=\"relative\">\n                    <div className=\"absolute -inset-1 rounded-full bg-gradient-to-r from-sky-700 to-blue-700 opacity-35 blur\" />\n                \n                    \n                    <Avatar className=\"relative h-8 w-8 ring-2 ring-white/20\">\n                      <AvatarFallback className=\"bg-gradient-to-br from-sky-700 to-blue-700 text-sm font-semibold text-white\">\n                        {currentUser?.name\n                          ?.split(\" \")\n                          .map((n) => n[0])\n                          .join(\"\")\n                          .toUpperCase() || \"U\"}\n                      </AvatarFallback>\n                    </Avatar>\n                  </div>\n                  <div className=\"flex flex-col\">\n                    <span className=\"font-semibold text-white\">\n                      {currentUser?.name || \"User\"}\n                    </span>\n                    <span className=\"text-xs text-slate-400\">\n                      {currentUser?.email || \"Email unavailable\"}\n                    </span>\n                    <span className={`mt-1 inline-flex w-fit items-center gap-1 rounded-full bg-gradient-to-r ${getRoleBadgeColor(currentUser?.role || \"\")} px-2 py-0.5 text-[10px] font-medium text-white`}>\n                      <Shield className=\"h-2.5 w-2.5\" />\n                      {getRoleLabel(currentUser?.role || \"\")}\n                    </span>\n                  </div>\n                </div>\n              </div>\n\n              {/* Menu Items */}\n              <div className=\"p-2\">\n                <DropdownMenuGroup>\n                  <DropdownMenuItem\n                    onClick={handleProfile}\n                    className=\"flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 text-slate-300 transition-colors hover:bg-white/5 hover:text-white focus:bg-white/5\"\n                