g-background\">\n        <div className=\"flex flex-col items-center gap-3\">\n          <div className=\"h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent\" />\n          <p className=\"text-sm text-muted-foreground\">Loading MajiScope...</p>\n        </div>\n      </div>\n    )\n  }\n\n  return (\n    <SidebarProvider defaultOpen={false}>\n      <TopbarTitleProvider>\n        <div className=\"flex w-full h-screen\">\n          <AppSidebar />\n          <div className=\"flex flex-col flex-1\">\n            <TopNavbar />\n            <SidebarInset className=\"relative m-0 min-h-[calc(100svh-3.5rem)] rounded-none bg-background\">\n              <main className=\"flex-1 overflow-y-auto overflow-x-hidden bg-background p-6 text-slate-900 dark:text-slate-100\">\n                {children}\n              </main>\n            </SidebarInset>\n          </div>\n        </div>\n      </TopbarTitleProvider>\n    </SidebarProvider>\n  )\n}\n","import * as React from 'react'\n\nconst MOBILE_BREAKPOINT = 768\n\nexport function useIsMobile() {\n  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)\n\n  React.useEffect(() => {\n    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)\n    const onChange = () => {\n      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)\n    }\n    mql.addEventListener('change', onChange)\n    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)\n    return () => mql.removeEventListener('change', onChange)\n  }, [])\n\n  return !!isMobile\n}\n","// packages/react/separator/src/Separator.tsx\nimport * as React from \"react\";\nimport { Primitive } from \"@radix-ui/react-primitive\";\nimport { jsx } from \"react/jsx-runtime\";\nvar NAME = \"Separator\";\nvar DEFAULT_ORIENTATION = \"horizontal\";\nvar ORIENTATIONS = [\"horizontal\", \"vertical\"];\nvar Separator = React.forwardRef((props, forwardedRef) => {\n  const { decorative, orientation: orientationProp = DEFAULT_ORIENTATI